// Cache statistics
class CacheStatistics implements Serializable {
    private static final long serialVersionUID = 1L;
    private long hits;
    private long misses;
    private long evictions;
    private long diskWrites;
    private long diskReads;

    public synchronized void recordHit() { hits++; }
    public synchronized void recordMiss() { misses++; }
    public synchronized void recordEviction() { evictions++; }
    public synchronized void recordDiskWrite() { diskWrites++; }
    public synchronized void recordDiskRead() { diskReads++; }

    public long getHits() { return hits; }
    public long getMisses() { return misses; }
    public long getEvictions() { return evictions; }
    public long getDiskWrites() { return diskWrites; }
    public long getDiskReads() { return diskReads; }

    public double getHitRate() {
        long total = hits + misses;
        return total == 0 ? 0.0 : (double) hits / total;
    }

    @Override
    public String toString() {
        return String.format("CacheStats{hits=%d, misses=%d, hitRate=%.2f%%, evictions=%d, diskWrites=%d, diskReads=%d}",
                hits, misses, getHitRate() * 100, evictions, diskWrites, diskReads);
    }
}

// Main disk-backed cache system
class DiskCache<T extends Serializable> {
    private final Path cacheDirectory;
    private final ConcurrentHashMap<String, CacheEntry<T>> memoryCache;
    private final ReadWriteLock lock;
    private final CacheStatistics statistics;
    private final int maxMemoryEntries;
    private final Duration defaultTtl;
    private final ScheduledExecutorService cleanupExecutor;

    public DiskCache(String cacheDir, int maxMemoryEntries, Duration defaultTtl) throws IOException {
        this.cacheDirectory = Paths.get(cacheDir);
        this.memoryCache = new ConcurrentHashMap<>();
        this.lock = new ReentrantReadWriteLock();
        this.statistics = new CacheStatistics();
        this.maxMemoryEntries = maxMemoryEntries;
        this.defaultTtl = defaultTtl;

        Files.createDirectories(cacheDirectory);

        // Schedule periodic cleanup
        cleanupExecutor = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "cache-cleanup");
            t.setDaemon(true);
            return t;
        });
        cleanupExecutor.scheduleAtFixedRate(this::cleanupExpired, 1, 1, TimeUnit.MINUTES);
    }

    public void put(String key, T value) {
        put(key, value, defaultTtl);
    }

    public void put(String key, T value, Duration ttl) {
        lock.writeLock().lock();
        try {
            CacheEntry<T> entry = new CacheEntry<>(key, value, ttl);

            // Evict if memory cache is full
            if (memoryCache.size() >= maxMemoryEntries && !memoryCache.containsKey(key)) {
                evictOldestEntry();
            }

            memoryCache.put(key, entry);
            writeToDisk(key, entry);
        } finally {
            lock.writeLock().unlock();
        }
    }

    @SuppressWarnings("unchecked")
    public Optional<T> get(String key) {
        lock.readLock().lock();
        try {
            // Check memory cache first
            CacheEntry<T> entry = memoryCache.get(key);
            if (entry != null) {
                if (entry.isExpired()) {
                    lock.readLock().unlock();
                    lock.writeLock().lock();
                    try {
                        remove(key);
                        statistics.recordMiss();
                        return Optional.empty();
                    } finally {
                        lock.writeLock().unlock();
                        lock.readLock().lock();
                    }
                }
                statistics.recordHit();
                return Optional.of(entry.getValue());
            }

            // Try disk cache
            entry = readFromDisk(key);
            if (entry != null) {
                if (entry.isExpired()) {
                    deleteDiskEntry(key);
                    statistics.recordMiss();
                    return Optional.empty();
                }

                // Promote to memory cache
                lock.readLock().unlock();
                lock.writeLock().lock();
                try {
                    if (memoryCache.size() >= maxMemoryEntries) {
                        evictOldestEntry();
                    }
                    memoryCache.put(key, entry);
                } finally {
                    lock.writeLock().unlock();
                    lock.readLock().lock();
                }

                statistics.recordHit();
                return Optional.of(entry.getValue());
            }

            statistics.recordMiss();
            return Optional.empty();
        } finally {
            lock.readLock().unlock();
        }
    }

    public T getOrCompute(String key, Callable<T> computation) throws Exception {
        return getOrCompute(key, computation, defaultTtl);
    }

    public T getOrCompute(String key, Callable<T> computation, Duration ttl) throws Exception {
        Optional<T> cached = get(key);
        if (cached.isPresent()) {
            return cached.get();
        }

        lock.writeLock().lock();
        try {
            // Double-check
            cached = get(key);
            if (cached.isPresent()) {
                return cached.get();
            }

            T result = computation.call();
            put(key, result, ttl);
            return result;
        } finally {
            lock.writeLock().unlock();
        }
    }

    public void remove(String key) {
        lock.writeLock().lock();
        try {
            memoryCache.remove(key);
            deleteDiskEntry(key);
        } finally {
            lock.writeLock().unlock();
        }
    }

    public void clear() {
        lock.writeLock().lock();
        try {
            memoryCache.clear();
            try {
                Files.walk(cacheDirectory)
                        .filter(p -> p.toString().endsWith(".cache"))
                        .forEach(p -> {
                            try {
                                Files.delete(p);
                            } catch (IOException e) {
                                System.err.println("Failed to delete cache file: " + p);
                            }
                        });
            } catch (IOException e) {
                System.err.println("Error clearing disk cache: " + e.getMessage());
            }
        } finally {
            lock.writeLock().unlock();
        }
    }

    public boolean containsKey(String key) {
        lock.readLock().lock();
        try {
            if (memoryCache.containsKey(key)) {
                CacheEntry<T> entry = memoryCache.get(key);
                return entry != null && !entry.isExpired();
            }
            Path path = getCacheFilePath(key);
            return Files.exists(path);
        } finally {
            lock.readLock().unlock();
        }
    }

    public int memorySize() {
        return memoryCache.size();
    }

    public int diskSize() {
        try {
            return (int) Files.walk(cacheDirectory)
                    .filter(p -> p.toString().endsWith(".cache"))
                    .count();
        } catch (IOException e) {
            return -1;
        }
    }

    public CacheStatistics getStatistics() {
        return statistics;
    }

    public void shutdown() {
        cleanupExecutor.shutdown();
        try {
            cleanupExecutor.awaitTermination(5, TimeUnit.SECONDS);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    private void writeToDisk(String key, CacheEntry<T> entry) {
        Path filePath = getCacheFilePath(key);
        try (ObjectOutputStream oos = new ObjectOutputStream(
                new BufferedOutputStream(new FileOutputStream(filePath.toFile())))) {
            oos.writeObject(entry);
            oos.flush();
            statistics.recordDiskWrite();
        } catch (IOException e) {
            System.err.println("Failed to write cache entry to disk: " + key + " - " + e.getMessage());
        }
    }

    @SuppressWarnings("unchecked")
    private CacheEntry<T> readFromDisk(String key) {
        Path filePath = getCacheFilePath(key);
        if (!Files.exists(filePath)) {
            return null;
        }
        try (ObjectInputStream ois = new ObjectInputStream(
                new BufferedInputStream(new FileInputStream(filePath.toFile())))) {
            statistics.recordDiskRead();
            return (CacheEntry<T>) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            System.err.println("Failed to read cache entry from disk: " + key + " - " + e.getMessage());
            deleteDiskEntry(key);
            return null;
        }
    }

    private void deleteDiskEntry(String key) {
        Path filePath = getCacheFilePath(key);
        try {
            Files.deleteIfExists(filePath);
        } catch (IOException e) {
            System.err.println("Failed to delete cache file: " + key);
        }
    }

    private Path getCacheFilePath(String key) {
        String safeKey = key.replaceAll("[^a-zA-Z0-9_-]", "_");
        return cacheDirectory.resolve(safeKey + ".cache");
    }

    private void evictOldestEntry() {
        String oldestKey = null;
        Instant oldestTime = Instant.MAX;

        for (Map.Entry<String, CacheEntry<T>> e : memoryCache.entrySet()) {
            if (e.getValue().getCreatedAt().isBefore(oldestTime)) {
                oldestTime = e.getValue().getCreatedAt();
                oldestKey = e.getKey();
            }
        }

        if (oldestKey != null) {
            memoryCache.remove(oldestKey);
            statistics.recordEviction();
        }
    }

    private void cleanupExpired() {
        lock.writeLock().lock();
        try {
            // Cleanup memory
            List<String> expiredKeys = new ArrayList<>();
            for (Map.Entry<String, CacheEntry<T>> entry : memoryCache.entrySet()) {
                if (entry.getValue().isExpired()) {
                    expiredKeys.add(entry.getKey());
                }
            }
            for (String key : expiredKeys) {
                memoryCache.remove(key);
                deleteDiskEntry(key);
                statistics.recordEviction();
            }

            // Cleanup disk entries not in memory
            try {
                Files.walk(cacheDirectory)
                        .filter(p -> p.toString().endsWith(".cache"))
                        .forEach(p -> {
                            try (ObjectInputStream ois = new ObjectInputStream(
                                    new BufferedInputStream(new FileInputStream(p.toFile())))) {
                                CacheEntry<?> entry = (CacheEntry<?>) ois.readObject();
                                if (entry.isExpired()) {
                                    Files.delete(p);
                                    statistics.recordEviction();
                                }
                            } catch (Exception e) {
                                try {
                                    Files.delete(p);
                                } catch (IOException ignored) {}
                            }
                        });
            } catch (IOException e) {
                System.err.println("Error during disk cleanup: " + e.getMessage());
            }
        } finally {
            lock.writeLock().unlock();
        }
    }
}

// Specialized cache manager for user preferences and sessions
class CacheManager {
    private final DiskCache<UserPreferences> preferencesCache;
    private final DiskCache<SessionData> sessionCache;
    private final DiskCache<ComputationResult> computationCache;

    public CacheManager(String baseCacheDir) throws IOException {
        this.preferencesCache = new DiskCache<>(
                baseCacheDir + "/preferences", 100, Duration.ofHours(24));
        this.sessionCache = new DiskCache<>(
                baseCacheDir + "/sessions", 500, Duration.ofMinutes(30));
        this.computationCache = new DiskCache<>(
                baseCacheDir + "/computations", 200, Duration.ofHours(1));
    }

    public void cacheUserPreferences(String userId, UserPreferences prefs) {
        preferencesCache.put("user_prefs_" + userId, prefs);
    }

    public Optional<UserPreferences> getUserPreferences(String userId) {
        return preferencesCache.get("user_prefs_" + userId);
    }

    public void cacheSession(String sessionId, SessionData session) {
        sessionCache.put("session_" + sessionId, session);
    }

    public Optional<SessionData> getSession(String sessionId) {
        return sessionCache.get("session_" + sessionId);
    }

    public void cacheComputationResult(String computationId, ComputationResult result) {
        computationCache.put("comp_" + computationId, result);
    }

    public Optional<ComputationResult> getComputationResult(String computationId) {
        return computationCache.get("comp_" + computationId);
    }

    public ComputationResult computeIfAbsent(String computationId, Callable<ComputationResult> computation) throws Exception {
        return computationCache.getOrCompute("comp_" + computationId, computation);
    }

    public void invalidateUserPreferences(String userId) {
        preferencesCache.remove("user_prefs_" + userId);
    }

    public void invalidateSession(String sessionId) {
        sessionCache.remove("session_" + sessionId);
    }

    public void clearAll() {
        preferencesCache.clear();
        sessionCache.clear();
        computationCache.clear();
    }

    public void printStatistics() {
        System.out.println("=== Cache Statistics ===");
        System.out.println("Preferences Cache: " + preferencesCache.getStatistics());
        System.out.println("  Memory entries: " + preferencesCache.memorySize() +
                ", Disk entries: " + preferencesCache.diskSize());
        System.out.println("Session Cache: " + sessionCache.getStatistics());
        System.out.println("  Memory entries: " + sessionCache.memorySize() +
                ", Disk entries: " + sessionCache.diskSize());
        System.out.println("Computation Cache: " + computationCache.getStatistics());
        System.out.println("  Memory entries: " + computationCache.memorySize() +
                ", Disk entries: " + computationCache.diskSize());
    }

    public void shutdown() {
        preferencesCache.shutdown();
        sessionCache.shutdown();
        computationCache.shutdown();
    }
}

// Main demo class
public class DiskCacheSystem {
    public static void main(String[] args) {
        try {
            String cacheDir = System.getProperty("java.io.tmpdir") + "/java_disk_cache_demo";
            System.out.println("Cache directory: " + cacheDir);
            System.out.println();

            CacheManager cacheManager = new CacheManager(cacheDir);

            // === Demo 1: User Preferences ===
            System.out.println("=== Demo 1: User Preferences Caching ===");

            UserPreferences prefs1 = new UserPreferences("user001");
            prefs1.setTheme("dark");
            prefs1.setLanguage("en");
            prefs1.setFontSize(16);
            prefs1.setNotificationsEnabled(true);
            prefs1.addCustomSetting("sidebar", "collapsed");
            prefs1.addCustomSetting("autoSave", "true");
            prefs1.addFavoriteCategory("Technology");
            prefs1.addFavoriteCategory("Science");

            cacheManager.cacheUserPreferences("user001", prefs1);
            System.out.println("Cached: " + prefs1);

            Optional<UserPreferences> retrieved = cacheManager.getUserPreferences("user001");
            retrieved.ifPresent(p -> System.out.println("Retrieved: " + p));

            // Cache miss
            Optional<UserPreferences> missing = cacheManager.getUserPreferences("nonexistent");
            System.out.println("Missing user result present: " + missing.isPresent());

            // Multiple users
            for (int i = 2; i <= 5; i++) {
                UserPreferences up = new UserPreferences("user00" + i);
                up.setTheme(i % 2 == 0 ? "light" : "dark");
                up.setLanguage(i % 3 == 0 ? "fr" : "en");
                up.setFontSize(12 + i);
                cacheManager.cacheUserPreferences("user00" + i, up);
            }
            System.out.println();

            // === Demo 2: Session Data ===
            System.out.println("=== Demo 2: Session Data Caching ===");

            SessionData session = new SessionData("sess_abc123", "user001");
            session.setIpAddress("192.168.1.100");
            session.setUserAgent("Mozilla/5.0");
            session.setAuthenticated(true);
            session.setAttribute("cart_items", new ArrayList<>(Arrays.asList("item1", "item2", "item3")));
            session.setAttribute("last_page", "/dashboard");
            session.addAccessLogEntry("Login at " + Instant.now());
            session.addAccessLogEntry("Accessed /dashboard");
            session.addAccessLogEntry("Accessed /settings");

            cacheManager.cacheSession("sess_abc123", session);
            System.out.println("Cached session: " + session);

            Optional<SessionData> retrievedSession = cacheManager.getSession("sess_abc123");
            retrievedSession.ifPresent(s -> {
                System.out.println("Retrieved session: " + s);
                System.out.println("  Cart items: " + s.getAttribute("cart_items"));
                System.out.println("  Access log: " + s.getAccessLog());
            });
            System.out.println();

            // === Demo 3: Expensive Computation Caching ===
            System.out.println("=== Demo 3: Expensive Computation Caching ===");

            // Simulate expensive computation
            long startTime = System.currentTimeMillis();
            ComputationResult compResult = cacheManager.computeIfAbsent("fibonacci_40", () -> {
                System.out.println("  Computing fibonacci(40)... (simulating expensive operation)");
                Thread.sleep(1000); // Simulate expensive computation
                long fib = computeFibonacci(40);
                long elapsed = System.currentTimeMillis() - startTime;
                ComputationResult result = new ComputationResult("fibonacci_40", fib, elapsed);
                result.addMetadata("algorithm", "recursive with memoization");
                result.addMetadata("input", "40");
                return result;
            });
            System.out.println("First call result: " + compResult);
            System.out.println("  Fibonacci(40) = " + compResult.getResult());

            // Second call should be from cache
            long startTime2 = System.currentTimeMillis();
            ComputationResult cachedResult = cacheManager.computeIfAbsent("fibonacci_40", () -> {
                System.out.println("  This should NOT be printed (cache hit expected)");
                return null;
            });
            long cacheRetrievalTime = System.currentTimeMillis() - startTime2;
            System.out.println("Second call result (from cache): " + cachedResult);
            System.out.println("  Cache retrieval time: " + cacheRetrievalTime + "ms");
            System.out.println();

            // === Demo 4: Direct DiskCache usage ===
            System.out.println("=== Demo 4: Direct DiskCache with TTL ===");

            DiskCache<String> stringCache = new DiskCache<>(cacheDir + "/strings", 10, Duration.ofSeconds(3));

            stringCache.put("greeting", "Hello, World!");
            stringCache.put("farewell", "Goodbye!", Duration.ofSeconds(1));

            System.out.println("greeting: " + stringCache.get("greeting").orElse("NOT FOUND"));
            System.out.println("farewell: " + stringCache.get("farewell").orElse("NOT FOUND"));

            System.out.println("Waiting 2 seconds for short TTL to expire...");
            Thread.sleep(2000);

            System.out.println("greeting (after 2s): " + stringCache.get("greeting").orElse("EXPIRED"));
            System.out.println("farewell (after 2s): " + stringCache.get("farewell").orElse("EXPIRED"));

            stringCache.shutdown();
            System.out.println();

            // === Demo 5: Eviction ===
            System.out.println("=== Demo 5: Memory Eviction ===");

            DiskCache<Integer> smallCache = new DiskCache<>(cacheDir + "/small", 3, Duration.ofMinutes(5));

            for (int i = 1; i <= 5; i++) {
                smallCache.put("num_" + i, i * 100);
                System.out.println("After putting num_" + i + ": memory=" +
                        smallCache.memorySize() + ", disk=" + smallCache.diskSize());
            }

            // All should still be retrievable from disk even if evicted from memory
            for (int i = 1; i <= 5; i++) {
                Optional<Integer> val = smallCache.get("num_" + i);
                System.out.println("num_" + i + " = " + val.orElse(-1));
            }

            System.out.println("Small cache stats: " + smallCache.getStatistics());
            smallCache.shutdown();
            System.out.println();

            // === Print Overall Statistics ===
            cacheManager.printStatistics();

            // Cleanup
            cacheManager.clearAll();
            cacheManager.shutdown();

            // Cleanup temp directory
            deleteDirectory(new File(cacheDir));
            System.out.println("\nCache directory cleaned up.");

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static long computeFibonacci(int n) {
        if (n <= 1) return n;
        long[] memo = new long[n + 1];
        memo[0] = 0;
        memo[1] = 1;
        for (int i = 2; i <= n; i++) {
            memo[i] = memo[i - 1] + memo[i - 2];
        }
        return memo[n];
    }

    private static void deleteDirectory(File dir) {
        if (dir.isDirectory()) {
            File[] children = dir.listFiles();
            if (children != null) {
                for (File child : children) {
                    deleteDirectory(child);
                }
            }
        }
        dir.delete();
    }
}